26	   * According to the spec, completion_tokens should include reasoning_tokens.
27	   *
28	   * Example of incorrect data from DeepInfra:
29	   * {
30	   *   "completion_tokens": 84,    // text-only tokens
31	   *   "completion_tokens_details": {
32	   *     "reasoning_tokens": 1081  // reasoning tokens not included above
33	   *   }
34	   * }
35	   *
36	   * This would result in negative text tokens: 84 - 1081 = -997
37	   *
38	   * The fix: If reasoning_tokens > completion_tokens, add reasoning_tokens
39	   * to completion_tokens: 84 + 1081 = 1165
40	   */
41	  private fixUsageForGeminiModels(usage: any): typeof usage {
42	    if (!usage || !usage.completion_tokens_details?.reasoning_tokens) {
43	      return usage;
44	    }
45	
46	    const completionTokens = usage.completion_tokens ?? 0;
47	    const reasoningTokens = usage.completion_tokens_details.reasoning_tokens;
48	
49	    // If reasoning tokens exceed completion tokens, the API data is incorrect
50	    // DeepInfra is returning only text tokens in completion_tokens, not including reasoning
51	    if (reasoningTokens > completionTokens) {
52	      const correctedCompletionTokens = completionTokens + reasoningTokens;
53	
54	      return {
55	        ...usage,
56	        // Add reasoning_tokens to completion_tokens to get the correct total
57	        completion_tokens: correctedCompletionTokens,
58	        // Update total_tokens if present
59	        total_tokens:
60	          usage.total_tokens != null
61	            ? usage.total_tokens + reasoningTokens
