75	    if (result.usage?.raw) {
76	      const fixedRawUsage = this.fixUsageForGeminiModels(result.usage.raw);
77	      if (fixedRawUsage !== result.usage.raw) {
78	        // Recalculate usage with fixed data
79	        const promptTokens = fixedRawUsage.prompt_tokens ?? 0;
80	        const completionTokens = fixedRawUsage.completion_tokens ?? 0;
