140	                  usage: {
141	                    inputTokens: {
142	                      total: promptTokens,
143	                      noCache: promptTokens - cacheReadTokens,
144	                      cacheRead: cacheReadTokens,
145	                      cacheWrite: undefined,
146	                    },
147	                    outputTokens: {
148	                      total: completionTokens,
149	                      text: completionTokens - reasoningTokens,
150	                      reasoning: reasoningTokens,
