### 6. **DeepInfra Chat Model Customization** (`deepinfra-chat-language-model.ts`)

DeepInfra extends `OpenAICompatibleChatLanguageModel` to fix a bug in token counting for Gemini/Gemma models:

```typescript
export class DeepInfraChatLanguageModel extends OpenAICompatibleChatLanguageModel {
  private fixUsageForGeminiModels(usage: any) {
    // DeepInfra returns completion_tokens without reasoning_tokens
    // Fix: add reasoning_tokens to completion_tokens
    if (reasoningTokens > completionTokens) {
      return {
        ...usage,
        completion_tokens: completionTokens + reasoningTokens,
        total_tokens: (usage.total_tokens ?? 0) + reasoningTokens,
      };
    }
    return usage;
  }

  async doGenerate(options) {
    const result = await super.doGenerate(options);
    if (result.usage?.raw) {
      result.usage = fixedUsage;
    }
    return result;
  }
}
```

**Pattern:** Inherit from OpenAI-compatible, override methods for API quirks.

