```

---

### 8. `packages/pixelart/src/version.ts`

```typescript
declare const __PACKAGE_VERSION__: string | undefined;
export const VERSION: string =
  typeof __PACKAGE_VERSION__ !== 'undefined'
    ? __PACKAGE_VERSION__
    : '0.0.0-test';
```

---

### 9. `packages/pixelart/src/pixelart-image-model-id.ts`

Defines the exported `PixelArtImageModelId` type and `PixelArtImageSettings` interface (provider options passable via `providerOptions.pixelart`):

```typescript
// Known fictional PixelArt model IDs
export type PixelArtImageModelId =
  | 'pixelart-standard'
  | 'pixelart-retro'
  | 'pixelart-8bit'
  | (string & {});

/**
 * Settings for the PixelArt image generation model,
 * passed via providerOptions.pixelart in generateImage().
 */
export interface PixelArtImageSettings {
  /**
   * Output image size (e.g. "512x512", "1024x1024").
   */
  size?: string;

  /**
   * Visual style of the generated pixel art.
   */
  style?: 'pixel' | 'retro' | '8bit';

  /**
   * Pixel density (dots-per-cell). Higher = more detailed pixels.
   */
  pixelDensity?: number;
}
```

---

### 10. `packages/pixelart/src/pixelart-image-model.ts`

Implements `ImageModelV3`. Key design decisions:
- Uses `parseProviderOptions` with a Zod schema to extract `size`, `style`, `pixelDensity` from `providerOptions.pixelart`
- Calls `POST https://api.pixelart.ai/v1/images/generations` via `postJsonToApi`
- Issues warnings for unsupported standard fields (`aspectRatio`, `seed`, `files`, `mask`)
- Returns images as base64 strings from the fictional `data[].b64_json` response field
- Uses `createJsonErrorResponseHandler` for error handling

```typescript
import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { FetchFunction, Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  parseProviderOptions,
  postJsonToApi,
  resolve,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import type { PixelArtImageModelId } from './pixelart-image-model-id';

// Internal config passed from the provider factory
interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: { currentDate?: () => Date };
}

// Zod schema for provider-specific options
const pixelArtImageSettingsSchema = z.object({
  size: z.string().optional(),
  style: z.enum(['pixel', 'retro', '8bit']).optional(),
  pixelDensity: z.number().optional(),
});

// Response schema for POST /images/generations
const pixelArtImageResponseSchema = z.object({
  created: z.number().nullish(),
  data: z.array(z.object({ b64_json: z.string() })),
});

// Error schema
const pixelArtErrorSchema = z.object({ error: z.object({ message: z.string() }) });

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: error => error.error.message,
});

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string { return this.config.provider; }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const { prompt, n, size, aspectRatio, seed, files, mask, providerOptions, abortSignal, headers } = options;
    const warnings: Array<SharedV3Warning> = [];

    // Parse provider-specific options
    const settings = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageSettingsSchema,
    });

    // Warn about unsupported standard parameters
    if (aspectRatio != null) {
      warnings.push({ type: 'unsupported-setting', setting: 'aspectRatio' });
    }
    if (seed != null) {
      warnings.push({ type: 'unsupported-setting', setting: 'seed' });
    }
    if (files != null && files.length > 0) {
      warnings.push({ type: 'other', message: 'Image editing (files) is not supported by PixelArt.' });
    }
    if (mask != null) {
      warnings.push({ type: 'other', message: 'Inpainting (mask) is not supported by PixelArt.' });
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(await resolve(this.config.headers), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        // Standard size from call options (overridden by providerOptions.pixelart.size)
        size: settings?.size ?? size,
        // PixelArt-specific settings
        style: settings?.style,
        pixel_density: settings?.pixelDensity,
      },
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(pixelArtImageResponseSchema),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}
```

---

### 11. `packages/pixelart/src/pixelart-provider.ts`

Exports `PixelArtProvider` interface, `PixelArtProviderSettings`, factory function `createPixelArt`, and default singleton `pixelart`:

```typescript
import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
import type { FetchFunction } from '@ai-sdk/provider-utils';
import { loadApiKey, withoutTrailingSlash, withUserAgentSuffix } from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import type { PixelArtImageModelId } from './pixelart-image-model-id';
import { VERSION } from './version';

export interface PixelArtProviderSettings {
  apiKey?: string;
  baseURL?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  image(modelId: PixelArtImageModelId): ImageModelV3;
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

const defaultBaseURL = 'https://api.pixelart.ai/v1';

export function createPixelArt(options: PixelArtProviderSettings = {}): PixelArtProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL: baseURL ?? defaultBaseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    specificationVersion: 'v3' as const,
    imageModel: createImageModel,
    image: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
    },
    embeddingModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
    },
  };
}

export const pixelart = createPixelArt();
```

---

### 12. `packages/pixelart/src/index.ts`

Public API surface:

```typescript
export type { PixelArtProvider, PixelArtProviderSettings } from './pixelart-provider';
export { createPixelArt, pixelart } from './pixelart-provider';
export type { PixelArtImageModelId, PixelArtImageSettings } from './pixelart-image-model-id';
export { VERSION } from './version';
```

---

## File to Update

### `tsconfig.json` (root)

Add `{ "path": "packages/pixelart" }` between `packages/perplexity` (line 40) and `packages/provider` (line 41) to keep alphabetical order:

```
    { "path": "packages/perplexity" },
+   { "path": "packages/pixelart" },
    { "path": "packages/provider" },
```

---

## Architecture Notes

- **No language/embedding models**: `languageModel` and `embeddingModel` throw `NoSuchModelError` — same pattern as `packages/fal`.
- **Provider options**: Settings (`size`, `style`, `pixelDensity`) are passed via `providerOptions.pixelart` at call time (not constructor), parsed with `parseProviderOptions` + Zod. This is the standard AI SDK pattern for provider-specific knobs.
- **Base URL precedence**: Provider-level `baseURL` setting overrides the default; the `size` in `providerOptions.pixelart` overrides the standard `size` from `ImageModelV3CallOptions`.
- **Imports**: Uses `zod/v4` (per AGENTS.md Zod guidance) and workspace dependencies only.

---

## Verification

1. **TypeScript compile**: From the repo root, run `pnpm type-check:full` — should pass with no errors in `packages/pixelart/`.
2. **Build**: From `packages/pixelart/`, run `pnpm build` — should produce `dist/index.js`, `dist/index.mjs`, and `dist/index.d.ts`.
3. **Exports check**: Confirm `createPixelArt`, `pixelart`, `PixelArtProvider`, `PixelArtImageModelId`, and `PixelArtImageSettings` are all importable from `@ai-sdk/pixelart`.
4. **Runtime smoke test**: Instantiate `createPixelArt({ apiKey: 'test' }).image('pixelart-standard')` and verify the returned object has `specificationVersion === 'v3'`, `provider === 'pixelart.image'`, `modelId === 'pixelart-standard'`, and `maxImagesPerCall === 4`.

