### 9. PROVIDER FACTORY FUNCTION IMPLEMENTATION PATTERN

Both providers follow this pattern:

```typescript
export function createGoogleGenerativeAI(
  options: GoogleGenerativeAIProviderSettings = {},
): GoogleGenerativeAIProvider {
  // 1. Set up base URL with defaults
  const baseURL = withoutTrailingSlash(options.baseURL) ?? 'https://...';
  const providerName = options.name ?? 'google.generative-ai';

  // 2. Create header factory function (resolvable)
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        'x-goog-api-key': loadApiKey({ ... }),
        ...options.headers,
      },
      `ai-sdk/google/${VERSION}`,
    );

  // 3. Create model factories for each type
  const createChatModel = (modelId) => new GoogleGenerativeAILanguageModel(...);
  const createImageModel = (modelId, settings) => new GoogleGenerativeAIImageModel(...);
  const createEmbeddingModel = (modelId) => new GoogleGenerativeAIEmbeddingModel(...);
  const createVideoModel = (modelId) => new GoogleGenerativeAIVideoModel(...);

  // 4. Create provider function (callable as default)
  const provider = function (modelId: GoogleGenerativeAIModelId) {
    if (new.target) {
      throw new Error('Cannot call with new keyword.');
    }
    return createChatModel(modelId);
  };

  // 5. Attach all methods and properties
  provider.specificationVersion = 'v3' as const;
  provider.languageModel = createChatModel;
  provider.chat = createChatModel;
  provider.image = createImageModel;
  provider.embedding = createEmbeddingModel;
  provider.video = createVideoModel;
  provider.tools = googleTools;

  return provider as GoogleGenerativeAIProvider;
}

// 6. Export default instance
export const google = createGoogleGenerativeAI();
```

