```typescript
export function createGoogleGenerativeAI(
  options: GoogleGenerativeAIProviderSettings = {},
): GoogleGenerativeAIProvider {
  // 1. Set up base URL with defaults
  const baseURL = withoutTrailingSlash(options.baseURL) ?? 'https://...';
  const providerName = options.name ?? 'google.generative-ai';

  // 2. Create header factory function (resolvable)
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        'x-goog-api-key': loadApiKey({ ... }),
        ...options.headers,
      },
      `ai-sdk/google/${VERSION}`,
    );

  // 3. Create model factories for each type
  const createChatModel = (modelId) => new GoogleGenerativeAILanguageModel(...);
  const createImageModel = (modelId, settings) => new GoogleGenerativeAIImageModel(...);
  const createEmbeddingModel = (modelId) => new GoogleGenerativeAIEmbeddingModel(...);
  const createVideoModel = (modelId) => new GoogleGenerativeAIVideoModel(...);

  // 4. Create provider function (callable as default)
  const provider = function (modelId: GoogleGenerativeAIModelId) {
    if (new.target) {
      throw new Error('Cannot call with new keyword.');
    }
    return createChatModel(modelId);
  };

  // 5. Attach all methods and properties
  provider.specificationVersion = 'v3' as const;
  provider.languageModel = createChatModel;
  provider.chat = createChatModel;
  provider.image = createImageModel;
  provider.embedding = createEmbeddingModel;
  provider.video = createVideoModel;
  provider.tools = googleTools;

  return provider as GoogleGenerativeAIProvider;
}

// 6. Export default instance
export const google = createGoogleGenerativeAI();
```

---

### 10. KEY ARCHITECTURAL PATTERNS

| Aspect | Pattern |
|--------|---------|
| **Package Structure** | Flat src/ directory with one model per file (e.g., `google-generative-ai-image-model.ts`) |
| **Exports** | Conditional exports for ESM/CJS via `exports` field in package.json |
| **Model Classes** | Implement specific `*ModelV3` interfaces from `@ai-sdk/provider` |
| **Provider Factory** | Function that returns callable object with methods for each model type |
| **Configuration** | Settings passed to model constructors; headers via getter functions (resolvable) |
| **API Calls** | Use utility functions from `@ai-sdk/provider-utils` (postJsonToApi, postFormDataToApi) |
| **Schemas** | Lazy-loaded Zod schemas for response validation |
| **Error Handling** | Provider-specific error handlers (e.g., `googleFailedResponseHandler`) |
| **Provider Naming** | Format: `{provider}.{model_type}` (e.g., "openai.image", "google.generative-ai") |
| **Image Model IDs** | Type unions with string literal models + `(string & {})` for extensibility |

---

### 11. SHARED V3 TYPES USED

All image models implement these types from `@ai-sdk/provider`:
- `ImageModelV3`: Main model interface
- `ImageModelV3CallOptions`: Input parameters
- `ImageModelV3File`: File/URL representation
- `ImageModelV3Usage`: Token usage information
- `SharedV3Warning`: Unsupported feature warnings
- `ProviderV3`: Base provider interface

---

This structure provides a clear, modular pattern for adding new AI providers with consistent interfaces across the entire SDK.

